def shift11(grid):
    rows=len(grid)
    cols=len(grid[0])
    result=[[0]*cols for _ in range(rows)]
    # copy 5s unchanged
    for r in range(rows):
        for c in range(cols):
            if grid[r][c]==5:
                result[r][c]=5
    for r in range(rows):
        # detect clusters? We'll just treat each '4' but shifting horizontally by 11 if dest empty and not 5?
        for c in range(cols):
            if grid[r][c]==4:
                dest=(c+11)%cols
                if result[r][dest]==0:
                    result[r][dest]=4
                else:
                    result[r][c]=4
        # This naive not maintain 2x2 clusters width.
