def apply_shift(grid):
    rows=len(grid)
    cols=len(grid[0])
    g=[row[:] for row in grid]
    moves=[]
    # Identify blocks (2x2 clusters)
    visited=[[False]*cols for _ in range(rows)]
    for r in range(rows):
        for c in range(cols):
            if g[r][c]==4 and not visited[r][c]:
                # BFS to get cluster cells
                stack=[(r,c)]
                coords=[]
                while stack:
                    x,y=stack.pop()
                    if 0<=x<rows and 0<=y<cols and g[x][y]==4 and not visited[x][y]:
                        visited[x][y]=True
                        coords.append((x,y))
                        for dx,dy in [(1,0),(-1,0),(0,1),(0,-1)]:
                            stack.append((x+dx,y+dy))
                # compute bbox
                minr=min(r for r,c2 in coords)
                minc=min(c2 for r,c2 in coords)
                maxr=max(r for r,c2 in coords)
                maxc=max(c2 for r,c2 in coords)
                if (maxr-minr)==1 and (maxc-minc)==1: # 2x2 block
                    if minc<10:
                        dest=minc+11
                    else:
                        dest=minc-11
                    # check dest within grid
                    if 0<=dest<=cols-2:
                        # check cells free (0)
                        free=True
                        for dr in [0,1]:
                            for dc in [0,1]:
                                if g[minr+dr][dest+dc]!=0:
                                    free=False
                        if free:
                            moves.append((coords, [(minr+dr,dest+dc) for dr in [0,1] for dc in [0,1]]))
    # perform moves
    for old,new in moves:
        for x,y in old:
            g[x][y]=0
        for x,y in new:
            g[x][y]=4
    return g
def grids_equal(a,b):
    return all(a[i][j]==b[i][j] for i in range(len(a)) for j in range(len(a[0])))
print("Example1 matches", grids_equal(apply_shift(input1), output1))
