def apply_shift(grid):
    rows=len(grid)
    cols=len(grid[0])
    g=[row[:] for row in grid]
    moves=[]
    visited=[[False]*cols for _ in range(rows)]
    for r in range(rows):
        for c in range(cols):
            if g[r][c]==4 and not visited[r][c]:
                # BFS cluster
                stack=[(r,c)]
                coords=[]
                while stack:
                    x,y=stack.pop()
                    if 0<=x<rows and 0<=y<cols and g[x][y]==4 and not visited[x][y]:
                        visited[x][y]=True
                        coords.append((x,y))
                        for dx,dy in [(1,0),(-1,0),(0,1),(0,-1)]:
                            stack.append((x+dx,y+dy))
                # compute bbox
                minr=min(r0 for r0,c0 in coords)
                minc=min(c0 for r0,c0 in coords)
                maxr=max(r0 for r0,c0 in coords)
                maxc=max(c0 for r0,c0 in coords)
                if maxr-minr==1 and maxc-minc==1:
                    if minc<10:
                        dest=minc+11
                    else:
                        dest=minc-11
                    if 0<=dest<=cols-2:
                        free=True
                        for dr in [0,1]:
                            for dc in [0,1]:
                                if g[minr+dr][dest+dc]!=0:
                                    free=False
                        if free:
                            moves.append((coords, [(minr+dr,dest+dc) for dr in [0,1] for dc in [0,1]]))
    for old,new in moves:
        for x,y in old:
            g[x][y]=0
        for x,y in new:
            g[x][y]=4
    return g
def equal(a,b):
    return all(a[r][c]==b[r][c] for r in range(len(a)) for c in range(len(a[0])))
print("Example1", equal(apply_shift(input1), output1))
